def translate_to_python(code: str) -> str:
    return DEMO_PYTHON

def generate_documentation(original_code: str, translated_code: str) -> str:
    return DEMO_DOCS

def generate_unit_tests(translated_code: str) -> str:
    return DEMO_TESTS

def generate_evaluation(original_code: str, translated_code: str) -> str:
    return DEMO_EVALUATION


@app.route('/', methods=['GET', 'POST'])
def index():
    translated    = ''
    documentation = ''
    unit_tests    = ''
    evaluation    = ''
    error         = ''
    original_code = ''

    if request.method == 'POST':
        original_code = request.form.get('java_code', '').strip()

        if 'file' in request.files:
            file = request.files['file']
            if file and file.filename != '':
                try:
                    original_code = file.read().decode('utf-8')
                except Exception:
                    error = 'Could not read uploaded file. Please ensure it is a text file.'

        if not original_code and not error:
            error = 'Please paste some code or upload a file to refactor.'
        elif original_code and not error:
            translated    = translate_to_python(original_code)
            documentation = generate_documentation(original_code, translated)
            unit_tests    = generate_unit_tests(translated)
            evaluation    = generate_evaluation(original_code, translated)

    return render_template('index.html',
                           translated=translated,
                           documentation=documentation,
                           unit_tests=unit_tests,
                           evaluation=evaluation,
                           error=error,
                           original_code=original_code)


if __name__ == '__main__':
    app.run(debug=True)